const LEVELS = [
  {min:0,    name:"🥚 Newbie",     color:"#7480a0"},
  {min:200,  name:"🐣 Beginner",   color:"#3ddc84"},
  {min:600,  name:"⚡ Learner",    color:"#4a9eff"},
  {min:1500, name:"🔥 Hacker",     color:"#ffb86c"},
  {min:3000, name:"💀 Elite",      color:"#ff5555"},
  {min:5000, name:"👑 Master",     color:"#ffd700"},
];
function getLevel(xp){let l=LEVELS[0];for(let x of LEVELS){if(xp>=x.min)l=x;}return l;}
function getNextLevel(xp){for(let l of LEVELS){if(xp<l.min)return l;}return null;}


